/**
 * Material Design 3 Expressive shape container element.
 *
 * Wraps content and clips it to one of 35 expressive shapes using SVG
 * clipPath. Supports interaction-driven morphing (hover, press, select)
 * and programmatic shape changes via attributes.
 *
 * @element ez-shape
 *
 * @attr {string} shape - Any of the 35 M3 Expressive shape names (kebab-case)
 * @attr {string} morph-to - Target shape to morph to on interaction
 * @attr {string} morph-on - Interaction triggers: "hover", "press", "select" (comma-separated)
 *
 * @example ```html
 * <!-- Static shape -->
 * <ez-shape shape="circle">
 *   <img src="avatar.jpg" alt="Avatar" />
 * </ez-shape>
 *
 * <!-- Morph on hover from circle to diamond -->
 * <ez-shape shape="circle" morph-to="diamond" morph-on="hover">
 *   <div class="content">Hello</div>
 * </ez-shape>
 *
 * <!-- Morph on press -->
 * <ez-shape shape="pill" morph-to="square" morph-on="press">
 *   <button>Click me</button>
 * </ez-shape>
 * ```
 */
export class EzShapeElement extends HTMLElement {
  static localName: string = EzShapeName;

  static get observedAttributes() {
    return observedAttrs;
  }

  #initialized = false;
  #svgEl: SVGSVGElement | null = null;
  #clipPathId = '';
  #shape: ShapeName = 'circle';
  #morphTo: ShapeName | '' = '';
  #morphOn = '';
  #isMorphed = false;
  #attrsChangedMap: Record<string, boolean> = {};

  get shape(): ShapeName {
    return this.#shape;
  }

  set shape(value: ShapeName) {
    if (SHAPE_NAMES.includes(value) && value !== this.#shape) {
      this.#shape = value;
      if (!this.#attrsChangedMap[SHAPE_ATTR]) {
        this.setAttribute(SHAPE_ATTR, value);
      } else {
        // eslint-disable-next-line @typescript-eslint/no-dynamic-delete
        delete this.#attrsChangedMap[SHAPE_ATTR];
      }
      this.#applyShape(value);
    }
  }

  get morphTo(): ShapeName | '' {
    return this.#morphTo;
  }

  set morphTo(value: ShapeName | '') {
    this.#morphTo = value;
    if (!this.#attrsChangedMap[MORPH_TO_ATTR]) {
      if (value) this.setAttribute(MORPH_TO_ATTR, value);
      else this.removeAttribute(MORPH_TO_ATTR);
    } else {
      // eslint-disable-next-line @typescript-eslint/no-dynamic-delete
      delete this.#attrsChangedMap[MORPH_TO_ATTR];
    }
  }

  get morphOn(): string {
    return this.#morphOn;
  }

  set morphOn(value: string) {
    this.#morphOn = value;
    if (!this.#attrsChangedMap[MORPH_ON_ATTR]) {
      if (value) this.setAttribute(MORPH_ON_ATTR, value);
      else this.removeAttribute(MORPH_ON_ATTR);
    } else {
      // eslint-disable-next-line @typescript-eslint/no-dynamic-delete
      delete this.#attrsChangedMap[MORPH_ON_ATTR];
    }
    this.#updateListeners();
  }

  connectedCallback() {
    if (!this.#initialized && this.isConnected) {
      this.#clipPathId = `ez-shape-clip-${_idCounter++}`;
      this.#shape = (this.getAttribute(SHAPE_ATTR) as ShapeName) ?? 'circle';
      this.#morphTo = (this.getAttribute(MORPH_TO_ATTR) as ShapeName) ?? '';
      this.#morphOn = this.getAttribute(MORPH_ON_ATTR) ?? '';

      this.#applyShape(this.#shape);
      this.#updateListeners();
      this.#initialized = true;
    }
  }

  disconnectedCallback() {
    if (this.#initialized) {
      this.#removeListeners();
      this.#removeSvg();
      this.#initialized = false;
    }
  }

  attributeChangedCallback(
    attrName: string,
    _prevValue: string | null,
    newValue: string | null
  ) {
    switch (attrName) {
      case SHAPE_ATTR:
        if (!this.#attrsChangedMap[SHAPE_ATTR]) {
          this.#attrsChangedMap[SHAPE_ATTR] = true;
          this.shape = (newValue as ShapeName) ?? 'circle';
        } else {
          // eslint-disable-next-line @typescript-eslint/no-dynamic-delete
          delete this.#attrsChangedMap[SHAPE_ATTR];
        }
        break;
      case MORPH_TO_ATTR:
        if (!this.#attrsChangedMap[MORPH_TO_ATTR]) {
          this.#attrsChangedMap[MORPH_TO_ATTR] = true;
          this.morphTo = (newValue as ShapeName) ?? '';
        } else {
          // eslint-disable-next-line @typescript-eslint/no-dynamic-delete
          delete this.#attrsChangedMap[MORPH_TO_ATTR];
        }
        break;
      case MORPH_ON_ATTR:
        if (!this.#attrsChangedMap[MORPH_ON_ATTR]) {
          this.#attrsChangedMap[MORPH_ON_ATTR] = true;
          this.morphOn = newValue ?? '';
        } else {
          // eslint-disable-next-line @typescript-eslint/no-dynamic-delete
          delete this.#attrsChangedMap[MORPH_ON_ATTR];
        }
        break;
      default:
        break;
    }
  }

  /**
   * Programmatically apply a shape to the element.
   */
  update() {
    this.#applyShape(
      this.#isMorphed && this.#morphTo ? this.#morphTo : this.#shape
    );
  }

  #applyShape(shapeName: ShapeName) {
    this.#ensureSvg(shapeName);
    this.style.clipPath = `url(#${this.#clipPathId})`;
    this.style.borderRadius = '';
  }

  #ensureSvg(shapeName: ShapeName) {
    const pathData = SVG_PATHS[shapeName];

    if (!pathData) return;

    if (!this.#svgEl) {
      this.#svgEl = document.createElementNS(
        'http://www.w3.org/2000/svg',
        'svg'
      );
      this.#svgEl.setAttribute('width', '0');
      this.#svgEl.setAttribute('height', '0');
      this.#svgEl.setAttribute('aria-hidden', 'true');
      this.#svgEl.style.position = 'absolute';
      this.#svgEl.style.pointerEvents = 'none';
      this.prepend(this.#svgEl);
    }

    const fillRule = EVENODD_SHAPES.has(shapeName)
      ? ' fill-rule="evenodd" clip-rule="evenodd"'
      : '';

    this.#svgEl.innerHTML =
      `<defs><clipPath id="${this.#clipPathId}" clipPathUnits="objectBoundingBox">` +
      `<path d="${pathData}"${fillRule} />` +
      `</clipPath></defs>`;
  }

  #removeSvg() {
    if (this.#svgEl) {
      this.#svgEl.remove();
      this.#svgEl = null;
    }
  }

  #updateListeners() {
    this.#removeListeners();

    const triggers = this.#morphOn.split(',').map(s => s.trim().toLowerCase());

    if (triggers.includes('hover')) {
      this.addEventListener('pointerenter', this.#onMorphIn);
      this.addEventListener('pointerleave', this.#onMorphOut);
    }

    if (triggers.includes('press')) {
      this.addEventListener('pointerdown', this.#onPressIn);
      this.addEventListener('pointerup', this.#onPressOut);
      this.addEventListener('pointercancel', this.#onPressOut);
    }
  }

  #removeListeners() {
    this.removeEventListener('pointerenter', this.#onMorphIn);
    this.removeEventListener('pointerleave', this.#onMorphOut);
    this.removeEventListener('pointerdown', this.#onPressIn);
    this.removeEventListener('pointerup', this.#onPressOut);
    this.removeEventListener('pointercancel', this.#onPressOut);
  }

  #onMorphIn = () => {
    if (this.#morphTo) {
      this.#isMorphed = true;
      this.#applyShape(this.#morphTo);
      this.dispatchEvent(
        new CustomEvent('ez-shape-morph', {
          detail: { from: this.#shape, to: this.#morphTo },
          bubbles: true,
        })
      );
    }
  };

  #onMorphOut = () => {
    if (this.#isMorphed) {
      this.#isMorphed = false;
      this.#applyShape(this.#shape);
      this.dispatchEvent(
        new CustomEvent('ez-shape-morph', {
          detail: { from: this.#morphTo, to: this.#shape },
          bubbles: true,
        })
      );
    }
  };

  #onPressIn = () => {
    const target = this.#morphTo || this.#shape;

    this.#applyShape(target);
  };

  #onPressOut = () => {
    const current =
      this.#isMorphed && this.#morphTo ? this.#morphTo : this.#shape;

    this.#applyShape(current);
  };
}

declare global {
  interface HTMLElementTagNameMap {
    'ez-shape': EzShapeElement;
  }
}

export { SHAPE_ATTR, MORPH_TO_ATTR, MORPH_ON_ATTR };
